[ApiController]
[Route("api/[controller]")]
public class FileUploadController : ControllerBase
{
    private readonly IWebHostEnvironment _environment;

    public FileUploadController(IWebHostEnvironment environment)
    {
        _environment = environment;
    }

    [HttpPost("avatar")]
    [RequestSizeLimit(5 * 1024 * 1024)]
    public async Task<IActionResult> UploadAvatar(IFormFile file)
    {
        if (file == null || file.Length == 0)
        {
            return BadRequest(new FileUploadResult
            {
                Success = false,
                ErrorMessage = "No file was provided or file is empty."
            });
        }

        var result = await SaveFileAsync(file, "avatars", FileUploadSettings.AllowedAvatarExtensions, FileUploadSettings.MaxAvatarSize);

        if (!result.Success)
        {
            return BadRequest(result);
        }

        return Ok(result);
    }

    [HttpPost("document")]
    [RequestSizeLimit(50 * 1024 * 1024)]
    public async Task<IActionResult> UploadDocument(IFormFile file)
    {
        if (file == null || file.Length == 0)
        {
            return BadRequest(new FileUploadResult
            {
                Success = false,
                ErrorMessage = "No file was provided or file is empty."
            });
        }

        var result = await SaveFileAsync(file, "documents", FileUploadSettings.AllowedDocumentExtensions, FileUploadSettings.MaxDocumentSize);

        if (!result.Success)
        {
            return BadRequest(result);
        }

        return Ok(result);
    }

    [HttpPost("documents")]
    [RequestSizeLimit(200 * 1024 * 1024)]
    public async Task<IActionResult> UploadMultipleDocuments(List<IFormFile> files)
    {
        if (files == null || files.Count == 0)
        {
            return BadRequest(new MultipleFileUploadResult
            {
                TotalFiles = 0,
                SuccessCount = 0,
                FailedCount = 0
            });
        }

        var multiResult = new MultipleFileUploadResult
        {
            TotalFiles = files.Count
        };

        foreach (var file in files)
        {
            if (file.Length == 0)
            {
                multiResult.FailedCount++;
                multiResult.Results.Add(new FileUploadResult
                {
                    Success = false,
                    FileName = file.FileName,
                    ErrorMessage = "File is empty."
                });
                continue;
            }

            var result = await SaveFileAsync(file, "documents", FileUploadSettings.AllowedDocumentExtensions, FileUploadSettings.MaxDocumentSize);
            multiResult.Results.Add(result);

            if (result.Success)
                multiResult.SuccessCount++;
            else
                multiResult.FailedCount++;
        }

        return Ok(multiResult);
    }

    [HttpDelete("{subfolder}/{fileName}")]
    public IActionResult DeleteFile(string subfolder, string fileName)
    {
        if (string.IsNullOrWhiteSpace(subfolder) || string.IsNullOrWhiteSpace(fileName))
        {
            return BadRequest("Invalid file path.");
        }

        // Sanitize to prevent directory traversal
        var safeSubfolder = Path.GetFileName(subfolder);
        var safeFileName = Path.GetFileName(fileName);

        var filePath = Path.Combine(_environment.WebRootPath, "uploads", safeSubfolder, safeFileName);

        if (!System.IO.File.Exists(filePath))
        {
            return NotFound("File not found.");
        }

        System.IO.File.Delete(filePath);

        return Ok(new { Success = true, Message = "File deleted successfully." });
    }

    private async Task<FileUploadResult> SaveFileAsync(IFormFile file, string subfolder, HashSet<string> allowedExtensions, long maxSize)
    {
        var extension = Path.GetExtension(file.FileName);

        if (string.IsNullOrEmpty(extension))
        {
            return new FileUploadResult
            {
                Success = false,
                FileName = file.FileName,
                ErrorMessage = "File has no extension."
            };
        }

        if (!allowedExtensions.Contains(extension))
        {
            return new FileUploadResult
            {
                Success = false,
                FileName = file.FileName,
                ErrorMessage = $"File type '{extension}' is not allowed. Allowed types: {string.Join(", ", allowedExtensions)}"
            };
        }

        if (file.Length > maxSize)
        {
            return new FileUploadResult
            {
                Success = false,
                FileName = file.FileName,
                ErrorMessage = $"File size ({file.Length} bytes) exceeds the maximum allowed size ({maxSize} bytes)."
            };
        }

        // Validate MIME type
        if (FileUploadSettings.AllowedMimeTypes.TryGetValue(extension, out var expectedMime))
        {
            if (!string.Equals(file.ContentType, expectedMime, StringComparison.OrdinalIgnoreCase)
                && !(extension.Equals(".jpg", StringComparison.OrdinalIgnoreCase) && file.ContentType.Equals("image/jpeg", StringComparison.OrdinalIgnoreCase)))
            {
                // Some flexibility for MIME types, but log a warning in production
            }
        }

        var uploadsFolder = Path.Combine(_environment.WebRootPath, "uploads", subfolder);
        Directory.CreateDirectory(uploadsFolder);

        // Generate a unique file name to prevent collisions
        var uniqueFileName = $"{Guid.NewGuid():N}{extension}";
        var filePath = Path.Combine(uploadsFolder, uniqueFileName);

        using (var stream = new FileStream(filePath, FileMode.Create))
        {
            await file.CopyToAsync(stream);
        }

        var relativePath = $"/uploads/{subfolder}/{uniqueFileName}";

        return new FileUploadResult
        {
            Success = true,
            FileName = uniqueFileName,
            FilePath = relativePath,
            FileSize = file.Length,
            ContentType = file.ContentType
        };
    }
